import React, { Suspense, lazy } from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { LanguageProvider } from './contexts/LanguageContext';
import { useLanguage } from './contexts/LanguageContext';
import { AppProvider } from '../core/state/AppContext';
import Meta from '@/components/Meta';
import LocaleRouteSync from '@/i18n/LocaleRouteSync';
// Fix import path to match actual directory structure
import { SimpleMedusaProvider } from './foundation/SimpleMedusaProvider';
import { initScroll } from '@/lib/scroll-minimal';
import AnalyticsProvider from '@/components/AnalyticsProvider';
import { MotionProvider } from '@/providers/MotionProvider';
import ScrollToTop from '@/components/ScrollToTop';

interface LocalizedMetaProps {
  pageKey: string;
  basePath: string; // German/default path, starts with '/'
  canonicalPath: string; // Current locale's canonical path, starts with '/'
}

const SITE_URL = import.meta.env.VITE_SITE_URL || 'https://www.muenchen-tattoo-studio.de';

const toEnglishPath = (basePath: string) => {
  if (basePath === '/') return '/en';
  return `/en${basePath}`;
};

const LocalizedMeta: React.FC<LocalizedMetaProps> = ({ pageKey, basePath, canonicalPath }) => {
  const { language, t } = useLanguage();

  const title = t(`common.meta.${pageKey}.title`);
  const description = t(`common.meta.${pageKey}.description`);

  return (
    <Meta
      title={title}
      description={description}
      canonicalPath={canonicalPath}
      hreflang={{
        de: `${SITE_URL}${basePath}`,
        en: `${SITE_URL}${toEnglishPath(basePath)}`,
      }}
      locale={language === 'en' ? 'en_US' : 'de_DE'}
      alternateLocale={language === 'en' ? ['de_DE'] : ['en_US']}
    />
  );
};

const homePageImport = import('./pages/HomePage');
const HomePage = lazy(() => homePageImport.then((m) => ({ default: m.HomePage })));
const TattooServicesPage = lazy(() =>
  import('@/components/pages/TattooServicesPage').then((m) => ({ default: m.TattooServicesPage })),
);
const PiercingServicesPage = lazy(() =>
  import('@/components/pages/PiercingServicesPage').then((m) => ({ default: m.PiercingServicesPage })),
);
const ArtistsPage = lazy(() => import('./pages/ArtistsPage').then((m) => ({ default: m.ArtistsPage })));
const GalleryPage = lazy(() => import('./pages/GalleryPage').then((m) => ({ default: m.GalleryPage })));
const BookingPage = lazy(() => import('./pages/BookingPage').then((m) => ({ default: m.BookingPage })));
const AftercarePage = lazy(() =>
  import('./pages/AftercarePage').then((m) => ({ default: m.AftercarePage })),
);
const LegalPage = lazy(() => import('./pages/LegalPage').then((m) => ({ default: m.LegalPage })));
const ImpressumPage = lazy(() =>
  import('./pages/ImpressumPage').then((m) => ({ default: m.ImpressumPage })),
);
const DatenschutzPage = lazy(() =>
  import('./pages/DatenschutzPage').then((m) => ({ default: m.DatenschutzPage })),
);
const AGBPage = lazy(() => import('./pages/AGBPage'));
const FAQPage = lazy(() => import('./pages/FAQPageNew').then((m) => ({ default: m.FAQPageNew })));
const ContactPage = lazy(() => import('./pages/ContactPage').then((m) => ({ default: m.ContactPage })));
const NotFoundPage = lazy(() => import('./pages/NotFoundPage').then((m) => ({ default: m.NotFoundPage })));

function App() {
  // Texture background is now handled in main.tsx

  return (
    <SimpleMedusaProvider>
      <AppProvider initialLanguage='DE'>
        <LanguageProvider>
          <MotionProvider config={{ scrollProgressEnabled: true, parallaxEnabled: true, cursorTrailEnabled: false }}>
            <LocaleRouteSync />
            <ScrollToTop />
            <AnalyticsProvider>
              {/* All page content (texture moved to main.tsx) */}
              <div className='relative z-10' data-scroll-root>
                {' '}
                {/* Content above texture */}
                <Suspense fallback={<div>Loading...</div>}>
                  <Routes>
                      {/* Main Routes */}
                      <Route
                        path='/'
                        element={
                          <>
                          <LocalizedMeta
                            pageKey='home'
                            basePath='/'
                            canonicalPath='/'
                          />
                          <HomePage />
                        </>
                      }
                    />
                    <Route path='/services' element={<Navigate to='/services/tattoos' replace />} />
                    <Route
                      path='/services/tattoos'
                      element={
                        <>
                          <LocalizedMeta
                            pageKey='services'
                            basePath='/services/tattoos'
                            canonicalPath='/services/tattoos'
                          />
                          <TattooServicesPage />
                        </>
                      }
                    />
                    <Route
                      path='/services/piercings'
                      element={
                        <>
                          <LocalizedMeta
                            pageKey='services'
                            basePath='/services/piercings'
                            canonicalPath='/services/piercings'
                          />
                          <PiercingServicesPage />
                        </>
                      }
                    />
                    <Route
                      path='/artists'
                      element={
                        <>
                          <LocalizedMeta
                            pageKey='artists'
                            basePath='/artists'
                            canonicalPath='/artists'
                          />
                          <ArtistsPage />
                        </>
                      }
                    />
                    <Route
                      path='/gallery'
                      element={
                        <>
                          <LocalizedMeta
                            pageKey='gallery'
                            basePath='/gallery'
                            canonicalPath='/gallery'
                          />
                          <GalleryPage />
                        </>
                      }
                    />
                    <Route
                      path='/booking'
                      element={
                        <>
                          <LocalizedMeta
                            pageKey='booking'
                            basePath='/booking'
                            canonicalPath='/booking'
                          />
                          <BookingPage />
                        </>
                      }
                    />

                    {/* 301 Redirect from old pricing page to services */}
                    <Route path='/pricing' element={<Navigate to='/services' replace />} />
                    <Route path='/preise' element={<Navigate to='/services' replace />} />

                    <Route path='/aftercare' element={<AftercarePage />} />
                    <Route
                      path='/agb'
                      element={
                        <>
                          <Meta
                            title='Medusa Tattoo München | AGB'
                            description='Vorläufige AGB-Seite. Verbindliche Fassung folgt in Kürze.'
                            canonicalPath='/agb'
                          />
                          <AGBPage />
                        </>
                      }
                    />
                                        <Route path='/legal' element={<LegalPage />} />
                    <Route path='/impressum' element={<ImpressumPage />} />
                    <Route path='/datenschutz' element={<DatenschutzPage />} />
                    <Route
                      path='/faq'
                      element={
                        <>
                          <LocalizedMeta
                            pageKey='faq'
                            basePath='/faq'
                            canonicalPath='/faq'
                          />
                          <FAQPage />
                        </>
                      }
                    />
                    <Route
                      path='/contact'
                      element={
                        <>
                          <LocalizedMeta
                            pageKey='contact'
                            basePath='/contact'
                            canonicalPath='/contact'
                          />
                          <ContactPage />
                        </>
                      }
                    />

                    {/* English Routes (path prefix) */}
                    <Route
                      path='/en'
                      element={
                        <>
                          <LocalizedMeta pageKey='home' basePath='/' canonicalPath='/en' />
                          <HomePage />
                        </>
                      }
                    />
                    <Route path='/en/services' element={<Navigate to='/en/services/tattoos' replace />} />
                    <Route
                      path='/en/services/tattoos'
                      element={
                        <>
                          <LocalizedMeta pageKey='services' basePath='/services/tattoos' canonicalPath='/en/services/tattoos' />
                          <TattooServicesPage />
                        </>
                      }
                    />
                    <Route
                      path='/en/services/piercings'
                      element={
                        <>
                          <LocalizedMeta pageKey='services' basePath='/services/piercings' canonicalPath='/en/services/piercings' />
                          <PiercingServicesPage />
                        </>
                      }
                    />
                    <Route
                      path='/en/artists'
                      element={
                        <>
                          <LocalizedMeta pageKey='artists' basePath='/artists' canonicalPath='/en/artists' />
                          <ArtistsPage />
                        </>
                      }
                    />
                    <Route
                      path='/en/gallery'
                      element={
                        <>
                          <LocalizedMeta pageKey='gallery' basePath='/gallery' canonicalPath='/en/gallery' />
                          <GalleryPage />
                        </>
                      }
                    />
                    <Route
                      path='/en/booking'
                      element={
                        <>
                          <LocalizedMeta pageKey='booking' basePath='/booking' canonicalPath='/en/booking' />
                          <BookingPage />
                        </>
                      }
                    />
                    <Route
                      path='/en/faq'
                      element={
                        <>
                          <LocalizedMeta pageKey='faq' basePath='/faq' canonicalPath='/en/faq' />
                          <FAQPage />
                        </>
                      }
                    />
                    <Route
                      path='/en/contact'
                      element={
                        <>
                          <LocalizedMeta pageKey='contact' basePath='/contact' canonicalPath='/en/contact' />
                          <ContactPage />
                        </>
                      }
                    />

                    {/* Legacy English mapping */}
                    <Route path='/en/pricing' element={<Navigate to='/en/services' replace />} />
                    <Route path='/en/preise' element={<Navigate to='/en/services' replace />} />

                    {/* 404 Route */}
                    <Route path='*' element={<NotFoundPage />} />
                </Routes>
              </Suspense>
            </div>{' '}
            {/* End content wrapper */}
          </AnalyticsProvider>
          </MotionProvider>
        </LanguageProvider>
      </AppProvider>
    </SimpleMedusaProvider>
  );
}

export default App;

import React from 'react';
import { Link } from 'react-router-dom';
import './ServiceCard.css';

/**
 * Service type for the curtain reveal card
 */
export interface Service {
  id: string;
  title: string;
  subtitle: string;
  description: string;
  icon: 'tattoo' | 'piercing';
  link: string;
}

interface ServiceCardProps {
  service: Service;
  isRevealed: boolean;
  index: number;
}

/**
 * ServiceCard - Japanese-inspired luxury service card with curtain reveal
 *
 * Adapted from ArtistCard with same animation system:
 * - Alternating two-column grid (icon left/right, text right/left)
 * - Curtain reveal animation (translate-x-full)
 * - Chrome accent lines and glow
 * - Deep black background
 * - 6 hover enhancements: Chrome Glow, Content Lift, Shadow Depth, Icon Zoom, Overlay Fade, Neighbor Shrink
 */
export function ServiceCard({ service, isRevealed, index }: ServiceCardProps) {
  const isEven = index % 2 === 0;

  return (
    <div
      className={`service-card-wrapper relative grid grid-cols-1 lg:grid-cols-2 gap-0 items-center ${
        isEven ? '' : 'lg:grid-flow-dense'
      }`}
      data-index={index}
      data-service={service.icon}
    >
      {/* Icon/visual container with curtain reveal and hover effects */}
      <div
        className={`service-card-image-container relative aspect-3/4 overflow-hidden bg-luxury-bg-dark-elevated ${
          isEven ? '' : 'lg:col-start-2'
        }`}
      >
        {/* Service type indicator */}
        <div
          className="service-category-indicator"
          title={service.icon.toUpperCase()}
          aria-label={service.icon.toUpperCase()}
        >
          <span className={`service-category-dot ${service.icon === 'piercing' ? 'service-category-dot--ring' : ''}`} />
        </div>

        {/* Icon/visual layer with zoom effect */}
        <div
          className={`absolute inset-0 flex items-center justify-center transition-opacity duration-700 ease-out ${
            isRevealed ? 'opacity-100' : 'opacity-0'
          }`}
        >
          {/* Service silhouette/icon */}
          <div className="service-card-icon">
            {service.icon === 'tattoo' ? (
              <svg
                viewBox="0 0 100 100"
                className="w-32 h-32 lg:w-48 lg:h-48"
                fill="none"
                stroke="currentColor"
                strokeWidth="1"
              >
                {/* Tattoo machine silhouette */}
                <path
                  d="M30 70 L40 30 L50 25 L60 30 L70 70 M35 50 L65 50 M45 25 L45 15 L55 15 L55 25"
                  className="text-white/20"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
                {/* Needle */}
                <path
                  d="M50 70 L50 85"
                  className="text-white/30"
                  strokeWidth="2"
                  strokeLinecap="round"
                />
              </svg>
            ) : (
              <svg
                viewBox="0 0 100 100"
                className="w-32 h-32 lg:w-48 lg:h-48"
                fill="none"
                stroke="currentColor"
                strokeWidth="1"
              >
                {/* Piercing needle silhouette */}
                <path
                  d="M20 50 L80 50 M75 45 L85 50 L75 55"
                  className="text-white/20"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
                {/* Jewelry ring */}
                <circle
                  cx="35"
                  cy="50"
                  r="12"
                  className="text-white/30"
                  strokeWidth="2"
                />
                {/* Ball */}
                <circle
                  cx="35"
                  cy="38"
                  r="4"
                  className="text-white/20"
                  fill="currentColor"
                />
              </svg>
            )}
          </div>
        </div>

        {/* Dark overlay that fades on hover */}
        <div className="service-card-overlay" />

        {/* Curtain reveal overlay - EXACT same as ArtistCard */}
        <div
          className={`absolute inset-0 bg-luxury-bg-dark-elevated transition-transform duration-900 ease-in-out origin-left ${
            isRevealed ? 'translate-x-full' : 'translate-x-0'
          }`}
          style={{ transitionDelay: '300ms' }}
        />

        {/* Border overlay */}
        <div
          className={`absolute inset-0 border border-white/10 transition-opacity duration-600 ${
            isRevealed ? 'opacity-100' : 'opacity-20'
          }`}
        />

        {/* Vertical chrome accent line */}
        <div
          className={`absolute top-0 ${
            isEven ? 'right-0' : 'left-0'
          } w-px h-full bg-linear-to-b from-transparent via-white/40 to-transparent transition-opacity duration-700 ${
            isRevealed ? 'opacity-100' : 'opacity-0'
          }`}
          style={{ transitionDelay: '450ms' }}
        />
      </div>

      {/* Text content with lift effect */}
      <div
        className={`relative px-8 lg:px-16 py-12 ${
          isEven ? 'lg:pl-20' : 'lg:pr-20'
        }`}
      >
        <div
          className={`service-card-content transition-all duration-1000 ease-out ${
            isRevealed
              ? 'opacity-100 translate-y-0'
              : 'opacity-0 translate-y-8'
          }`}
          style={{ transitionDelay: '800ms' }}
        >
          {/* Index number and divider */}
          <div className="mb-4">
            <div className="flex items-center gap-4 mb-2">
              <span className="text-luxury-text-inverse/40 text-sm font-light tracking-widest uppercase">
                {String(index + 1).padStart(2, '0')}
              </span>
              <div className="h-px grow bg-luxury-text-inverse/10" />
            </div>
            {/* Service title with chrome underline on hover */}
            <h3 className="service-card-name text-luxury-text-inverse text-4xl lg:text-5xl xl:text-6xl font-light tracking-tight leading-none">
              {service.title}
            </h3>
          </div>

          {/* Chrome underline */}
          <div
            className="mb-8 h-px bg-linear-to-r from-luxury-text-inverse/40 to-transparent"
            style={{ width: '60%' }}
          />

          {/* Subtitle */}
          <p className="text-luxury-text-inverse/60 text-sm tracking-wider uppercase mb-6 font-light">
            {service.subtitle}
          </p>

          {/* Description */}
          <p className="text-luxury-text-inverse/70 text-base lg:text-lg leading-relaxed font-light max-w-xl mb-8">
            {service.description}
          </p>

          {/* CTA Button */}
          <Link
            to={service.link}
            className="service-card-cta inline-flex items-center gap-3 px-6 py-3 border border-white/20 hover:border-white/40 transition-all duration-300"
          >
            <span className="text-luxury-text-inverse text-sm tracking-wider uppercase font-light">
              Mehr erfahren
            </span>
            <svg
              className="w-4 h-4 text-luxury-text-inverse/60"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
            >
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 5l7 7-7 7" />
            </svg>
          </Link>
        </div>

        {/* Side chrome accent line */}
        <div
          className={`absolute ${
            isEven ? 'left-0' : 'right-0'
          } top-0 bottom-0 w-px bg-linear-to-b from-transparent via-luxury-text-inverse/20 to-transparent transition-opacity duration-1000 ${
            isRevealed ? 'opacity-100' : 'opacity-0'
          }`}
          style={{ transitionDelay: '1000ms' }}
        />
      </div>

      {/* Loading pulse overlay */}
      <div
        className={`absolute inset-0 pointer-events-none transition-opacity duration-2000 ${
          isRevealed ? 'opacity-0' : 'opacity-100'
        }`}
      >
        <div className="absolute inset-0 flex items-center justify-center">
          <div className="w-px h-0 bg-white/20 animate-pulse" />
        </div>
      </div>
    </div>
  );
}

export default ServiceCard;

