import React, { useState } from 'react';

interface NewsletterFormProps {
  onSubmit: (email: string) => Promise<void>;
  className?: string;
}

export const NewsletterForm: React.FC<NewsletterFormProps> = ({ onSubmit, className = '' }) => {
  const [email, setEmail] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const validateEmail = (email: string): boolean => {
    return /\S+@\S+\.\S+/.test(email);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!email) {
      setError('Bitte geben Sie Ihre E-Mail-Adresse ein');
      return;
    }

    if (!validateEmail(email)) {
      setError('Bitte geben Sie eine gültige E-Mail-Adresse ein');
      return;
    }

    setIsSubmitting(true);

    try {
      await onSubmit(email);
      setIsSuccess(true);
      setEmail('');
    } catch (_err) {
      setError('Ein Fehler ist aufgetreten. Bitte versuchen Sie es später erneut.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className={`space-y-4 ${className}`}>
      <div>
        <label htmlFor='newsletter-email' className='sr-only'>
          E-Mail Adresse
        </label>
        <div className='relative'>
          <input
            id='newsletter-email'
            type='email'
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder='Ihre E-Mail-Adresse'
            className={`w-full px-4 py-3 rounded-lg bg-white/10 border
              ${error ? 'border-red-500' : 'border-brand-chrome/30'}
              text-luxury-text-inverse placeholder-luxury-text-inverse/50 focus:outline-none focus:ring-2 focus:ring-brand-accent`}
            required
            disabled={isSubmitting}
            aria-invalid={!!error}
            aria-describedby={error ? 'newsletter-error' : undefined}
          />
          {error && (
            <p id='newsletter-error' className='mt-0 text-sm text-red-500' role='alert'>
              {error}
            </p>
          )}
          {isSuccess && (
            <p className='mt-0 text-sm text-green-500' role='status'>
              Danke für Ihre Anmeldung!
            </p>
          )}
        </div>
      </div>

      <button
        type='submit'
        disabled={isSubmitting || isSuccess}
        className={`w-full px-6 py-3 text-base font-medium rounded-lg
          ${
            isSuccess
              ? 'bg-[var(--accent-chrome)] text-[var(--deep-black)] cursor-default'
              : 'bg-[var(--accent-chrome)] text-luxury-text-inverse hover:bg-[var(--accent-chrome)]/80'
          } transition-colors disabled:opacity-50`}
      >
        {isSubmitting
          ? 'Wird angemeldet...'
          : isSuccess
            ? 'Erfolgreich angemeldet'
            : 'Newsletter abonnieren'}
      </button>
    </form>
  );
};

export default NewsletterForm;

import {
  KeyboardEvent,
  useCallback,
  useEffect,
  useRef,
  useState,
  KeyboardEventHandler,
  RefObject,
  FocusEventHandler,
} from 'react';

type KeyHandler = (event: KeyboardEvent) => void;
type FocusHandler = (event: React.FocusEvent) => void;

interface UseKeyboardNavOptions {
  /**
   * Whether the keyboard navigation is currently active
   * @default true
   */
  isActive?: boolean;
  /**
   * Callback when the Escape key is pressed
   */
  onEscape?: KeyHandler;
  /**
   * Callback when the Enter key is pressed
   */
  onEnter?: KeyHandler;
  /**
   * Callback when the Space key is pressed
   */
  onSpace?: KeyHandler;
  /**
   * Callback when the ArrowUp key is pressed
   */
  onArrowUp?: KeyHandler;
  /**
   * Callback when the ArrowDown key is pressed
   */
  onArrowDown?: KeyHandler;
  /**
   * Callback when the ArrowLeft key is pressed
   */
  onArrowLeft?: KeyHandler;
  /**
   * Callback when the ArrowRight key is pressed
   */
  onArrowRight?: KeyHandler;
  /**
   * Callback when the Tab key is pressed
   */
  onTab?: KeyHandler;
  /**
   * Callback when the Home key is pressed
   */
  onHome?: KeyHandler;
  /**
   * Callback when the End key is pressed
   */
  onEnd?: KeyHandler;
  /**
   * Callback when any key is pressed
   */
  onKeyDown?: KeyHandler;
  /**
   * Callback when the element gains focus
   */
  onFocus?: FocusHandler;
  /**
   * Callback when the element loses focus
   */
  onBlur?: FocusHandler;
}

/**
 * Hook for managing keyboard navigation and focus states
 * @param options Configuration options for keyboard navigation
 * @returns Object containing event handlers and focus state
 */
export function useKeyboardNav({
  isActive = true,
  onEscape,
  onEnter,
  onSpace,
  onArrowUp,
  onArrowDown,
  onArrowLeft,
  onArrowRight,
  onTab,
  onHome,
  onEnd,
  onKeyDown,
  onFocus,
  onBlur,
}: UseKeyboardNavOptions = {}) {
  const [isFocused, setIsFocused] = useState(false);
  const elementRef = useRef<HTMLElement>(null);

  const handleKeyDown = useCallback(
    (event: KeyboardEvent) => {
      if (!isActive) return;

      // Call the appropriate handler based on the key
      switch (event.key) {
        case 'Escape':
          onEscape?.(event);
          break;
        case 'Enter':
          onEnter?.(event);
          break;
        case ' ':
          onSpace?.(event);
          break;
        case 'ArrowUp':
          onArrowUp?.(event);
          break;
        case 'ArrowDown':
          onArrowDown?.(event);
          break;
        case 'ArrowLeft':
          onArrowLeft?.(event);
          break;
        case 'ArrowRight':
          onArrowRight?.(event);
          break;
        case 'Tab':
          onTab?.(event);
          break;
        case 'Home':
          onHome?.(event);
          break;
        case 'End':
          onEnd?.(event);
          break;
        default:
          break;
      }

      // Call the user's keydown handler if provided
      onKeyDown?.(event);
    },
    [
      isActive,
      onEscape,
      onEnter,
      onSpace,
      onArrowUp,
      onArrowDown,
      onArrowLeft,
      onArrowRight,
      onTab,
      onHome,
      onEnd,
      onKeyDown,
    ],
  );

  // Handle focus events
  const handleFocus = useCallback<FocusEventHandler>(
    (event) => {
      setIsFocused(true);
      onFocus?.(event);
    },
    [onFocus],
  );

  // Handle blur events
  const handleBlur = useCallback<FocusEventHandler>(
    (event) => {
      setIsFocused(false);
      onBlur?.(event);
    },
    [onBlur],
  );

  // Set up event listeners for focus management
  useEffect(() => {
    const element = elementRef.current;
    if (!element) return;

    element.addEventListener('focusin', handleFocus as any);
    element.addEventListener('focusout', handleBlur as any);

    return () => {
      element.removeEventListener('focusin', handleFocus as any);
      element.removeEventListener('focusout', handleBlur as any);
    };
  }, [handleFocus, handleBlur]);

  // Return the event handlers and focus state
  return {
    onKeyDown: handleKeyDown as unknown as React.KeyboardEventHandler<HTMLElement>,
    onFocus: handleFocus,
    onBlur: handleBlur,
    isFocused,
    ref: elementRef as RefObject<HTMLElement>,
  };
}

interface FocusManagementReturn {
  /**
   * Whether the element is currently focused
   */
  isFocused: boolean;
  /**
   * Focus event handler
   */
  onFocus: FocusEventHandler;
  /**
   * Blur event handler
   */
  onBlur: FocusEventHandler;
  /**
   * Ref to attach to the element
   */
  ref: RefObject<HTMLElement>;
}

/**
 * Hook for managing focus within a component
 * @returns Object containing focus state and event handlers
 */
export const useFocusManagement = (): FocusManagementReturn => {
  const [isFocused, setIsFocused] = useState(false);
  const elementRef = useRef<HTMLElement>(null);

  const handleFocus = useCallback<FocusEventHandler>((event) => {
    setIsFocused(true);
  }, []);

  const handleBlur = useCallback<FocusEventHandler>((event) => {
    setIsFocused(false);
  }, []);

  return {
    isFocused,
    onFocus: handleFocus,
    onBlur: handleBlur,
    ref: elementRef,
  };
};

interface ListNavigationOptions {
  /**
   * Initial selected index
   */
  initialIndex?: number;
  /**
   * Whether to wrap around when navigating past the first or last item
   */
  wrapAround?: boolean;
  /**
   * Whether to focus the selected item
   */
  autoFocus?: boolean;
}

interface ListNavigationReturn {
  /**
   * Currently selected index
   */
  selectedIndex: number;
  /**
   * Set the selected index
   */
  setSelectedIndex: (index: number) => void;
  /**
   * Key down event handler for navigation
   */
  onKeyDown: React.KeyboardEventHandler;
  /**
   * Ref for the container element
   */
  containerRef: RefObject<HTMLElement>;
}

/**
 * Hook for managing keyboard navigation in a list
 * @param itemCount Number of items in the list
 * @param onSelect Callback when an item is selected
 * @param options Configuration options
 * @returns Object containing event handlers and selected index
 */
export const useListNavigation = (
  itemCount: number,
  onSelect: (index: number) => void,
  options: ListNavigationOptions = {},
): ListNavigationReturn => {
  const { initialIndex = 0, wrapAround = true, autoFocus = false } = options;
  const [selectedIndex, setSelectedIndex] = useState(initialIndex);
  const containerRef = useRef<HTMLElement>(null);

  // Focus the selected item when it changes
  useEffect(() => {
    if (autoFocus && containerRef.current) {
      const items = containerRef.current.querySelectorAll<HTMLElement>('[role="option"]');
      if (items[selectedIndex]) {
        items[selectedIndex].focus();
      }
    }
  }, [selectedIndex, autoFocus]);

  // Handle keyboard navigation
  const handleKeyDown = useCallback<React.KeyboardEventHandler>(
    (event) => {
      if (itemCount === 0) return;

      let newIndex = selectedIndex;

      switch (event.key) {
        case 'ArrowDown':
          event.preventDefault();
          newIndex = wrapAround
            ? (selectedIndex + 1) % itemCount
            : Math.min(selectedIndex + 1, itemCount - 1);
          break;
        case 'ArrowUp':
          event.preventDefault();
          newIndex = wrapAround
            ? (selectedIndex - 1 + itemCount) % itemCount
            : Math.max(selectedIndex - 1, 0);
          break;
        case 'Home':
          event.preventDefault();
          newIndex = 0;
          break;
        case 'End':
          event.preventDefault();
          newIndex = itemCount - 1;
          break;
        case 'Enter':
        case ' ':
          event.preventDefault();
          onSelect(selectedIndex);
          return; // Don't update the selected index
        default:
          return; // Don't update the selected index for other keys
      }

      setSelectedIndex(newIndex);
    },
    [itemCount, onSelect, selectedIndex, wrapAround],
  );

  return {
    selectedIndex,
    setSelectedIndex,
    onKeyDown: handleKeyDown,
    containerRef,
  };
};

import { useEffect, useState, useLayoutEffect } from 'react';

// Add type declaration for Vite's import.meta.env
interface ImportMetaEnv {
  DEV: boolean;
  PROD: boolean;
  MODE: string;
}

// Use useLayoutEffect on client, useEffect on server
const useIsomorphicLayoutEffect = typeof window !== 'undefined' ? useLayoutEffect : useEffect;

/**
 * Debounce function to limit the rate at which a function is called
 */
const debounce = <T extends (...args: unknown[]) => void>(
  fn: T,
  ms = 300,
): ((...args: Parameters<T>) => void) => {
  let timeoutId: ReturnType<typeof setTimeout>;
  return (...args: Parameters<T>) => {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn(...args), ms);
  };
};

/**
 * Hook to check if a media query matches
 * @param query Media query string (e.g. "(min-width: 768px)")
 * @returns boolean indicating if the media query matches
 */
export const useMediaQuery = (query: string): boolean => {
  // Track hydration/mounting status
  const [isHydrated, setIsHydrated] = useState(false);
  const [matches, setMatches] = useState(false);

  // Effect to handle hydration
  useIsomorphicLayoutEffect(() => {
    setIsHydrated(true);
    return () => setIsHydrated(false);
  }, []);

  useIsomorphicLayoutEffect(() => {
    // Skip if not hydrated or no window
    if (!isHydrated || typeof window === 'undefined') return;

    // Create media query list
    const mediaQuery = window.matchMedia(query);

    // Create handler function
    const handler = () => {
      if (isHydrated) {
        setMatches(mediaQuery.matches);
      }
    };

    // Set initial value and add listeners
    handler();

    // Create debounced resize handler
    const debouncedResizeHandler = debounce(() => {
      handler();
    }, 100);

    // Add listeners
    mediaQuery.addListener(handler);
    window.addEventListener('resize', debouncedResizeHandler);

    // Cleanup
    return () => {
      mediaQuery.removeListener(handler);
      window.removeEventListener('resize', debouncedResizeHandler);
    };
  }, [query, isHydrated]);

  return matches;
};

/**
 * Available breakpoints based on design tokens
 */
export type Breakpoint = 'mobile' | 'tablet' | 'desktop';

/**
 * Hook to get current breakpoint
 * @returns Current breakpoint ('mobile' | 'tablet' | 'desktop')
 */
export const useBreakpoint = (): Breakpoint => {
  const isTablet = useMediaQuery('(min-width: 768px)');
  const isDesktop = useMediaQuery('(min-width: 1200px)');

  if (isDesktop) return 'desktop';
  if (isTablet) return 'tablet';
  return 'mobile';
};

/**
 * Hook to get responsive value based on current breakpoint
 * @param mobile Value for mobile breakpoint
 * @param tablet Value for tablet breakpoint
 * @param desktop Value for desktop breakpoint
 * @returns Value for current breakpoint
 */
export const useResponsive = <T>(mobile: T, tablet: T, desktop: T): T => {
  const [isHydrated, setIsHydrated] = useState(false);
  const breakpoint = useBreakpoint();

  useIsomorphicLayoutEffect(() => {
    setIsHydrated(true);
    return () => setIsHydrated(false);
  }, []);

  // Return mobile value until hydrated
  if (!isHydrated) return mobile;

  // Log for debugging
  if (import.meta.env.DEV) {
    console.groupCollapsed('[useResponsive] Debug Info');
    console.log('Current breakpoint:', breakpoint);
    console.log('Values:', { mobile, tablet, desktop });
    console.groupEnd();
  }

  switch (breakpoint) {
    case 'desktop':
      return desktop;
    case 'tablet':
      return tablet;
    default:
      return mobile;
  }
};

import { z } from 'zod';

// Environment variable schema
const envSchema = z.object({
  // Required for production
  VITE_SITE_URL: z.string().url().describe('Base URL for the website'),

  // Business information (for LocalBusiness schema)
  VITE_BUSINESS_NAME: z.string().describe('Business name'),
  VITE_BUSINESS_PHONE: z.string().describe('Business phone number'),
  VITE_BUSINESS_EMAIL: z.string().email().describe('Business email'),
  VITE_BUSINESS_STREET: z.string().describe('Street address'),
  VITE_BUSINESS_POSTAL: z.string().describe('Postal code'),
  VITE_BUSINESS_CITY: z.string().describe('City'),
  VITE_BUSINESS_COUNTRY: z.string().describe('Country code'),
  VITE_WHATSAPP: z.string().describe('WhatsApp number'),
  VITE_OPENING_HOURS: z.string().describe('Opening hours'),

  // Geographic coordinates
  VITE_GEO_LAT: z.string().describe('Latitude'),
  VITE_GEO_LNG: z.string().describe('Longitude'),

  // Optional but recommended
  VITE_GA4_MEASUREMENT_ID: z
    .string()
    .startsWith('G-')
    .optional()
    .describe('Google Analytics 4 Measurement ID'),

  VITE_GOOGLE_MAPS_API_KEY: z
    .string()
    .optional()
    .describe('Google Maps API key for location services'),

  // Social media
  VITE_INSTAGRAM_URL: z.string().url().optional().describe('Instagram URL'),
  VITE_FACEBOOK_URL: z.string().url().optional().describe('Facebook URL'),

  // Business details
  VITE_PRICE_RANGE: z.string().optional().describe('Price range'),
  VITE_CURRENCIES_ACCEPTED: z.string().optional().describe('Accepted currencies'),
  VITE_PAYMENT_METHODS: z.string().optional().describe('Payment methods'),

  // Build-time variables
  NODE_ENV: z.enum(['development', 'production', 'test']).default('development'),

  // Contact form
  VITE_EMAIL_SERVICE_ID: z.string().optional().describe('Email service ID'),
  VITE_EMAIL_TEMPLATE_ID: z.string().optional().describe('Email template ID'),
  VITE_EMAIL_PUBLIC_KEY: z.string().optional().describe('Email public key'),

  // Development
  VITE_APP_ENV: z.string().optional().describe('App environment'),
  VITE_DEBUG: z
    .string()
    .transform((val) => val === 'true')
    .optional()
    .describe('Enable debug logging'),
});

// Parse and validate environment variables
function parseEnv() {
  // Handle both browser and Node.js environments
  const envSource =
    typeof import.meta !== 'undefined' && import.meta.env ? import.meta.env : process.env;

  try {
    const parsed = envSchema.parse(envSource);

    // Development warnings
    if (parsed.NODE_ENV === 'production') {
      if (!parsed.VITE_GA4_MEASUREMENT_ID) {
        console.warn('⚠️ GA4_MEASUREMENT_ID not set - analytics disabled');
      }
      if (!parsed.VITE_GOOGLE_MAPS_API_KEY) {
        console.warn('⚠️ GOOGLE_MAPS_API_KEY not set - maps will show fallback');
      }
    }

    return parsed;
  } catch (error) {
    if (error instanceof z.ZodError) {
      console.error('❌ Environment variable validation failed:');
      error.issues.forEach((issue) => {
        console.error(`  - ${issue.path.join('.')}: ${issue.message}`);
      });

      // In production, fail hard
      if (envSource?.NODE_ENV === 'production') {
        throw new Error('Invalid environment configuration');
      }
    }
    throw error;
  }
}

// Export validated environment
export const env = parseEnv();

// Type-safe environment interface
export type Env = z.infer<typeof envSchema>;

// Utility functions
export const isDevelopment = env.NODE_ENV === 'development';
export const isProduction = env.NODE_ENV === 'production';
export const isDebug = env.VITE_DEBUG || isDevelopment;

// Feature flags based on env
export const features = {
  analytics: !!env.VITE_GA4_MEASUREMENT_ID,
  maps: !!env.VITE_GOOGLE_MAPS_API_KEY,
  contact: !!env.VITE_BUSINESS_EMAIL,
  whatsapp: !!env.VITE_WHATSAPP,
  social: !!(env.VITE_INSTAGRAM_URL || env.VITE_FACEBOOK_URL),
  debug: isDebug,
} as const;

// Validation helper for components
export function requireEnv<K extends keyof Env>(key: K): NonNullable<Env[K]> {
  const value = env[key];
  if (!value) {
    throw new Error(`Required environment variable ${key} is not set`);
  }
  return value as NonNullable<Env[K]>;
}

// Development helper to show env status
if (isDevelopment) {
  console.table({
    'Site URL': env.VITE_SITE_URL,
    'Business Name': env.VITE_BUSINESS_NAME,
    Analytics: features.analytics ? '✅' : '❌',
    Maps: features.maps ? '✅' : '❌',
    WhatsApp: features.whatsapp ? '✅' : '❌',
    'Social Media': features.social ? '✅' : '❌',
    Environment: env.NODE_ENV,
  });
}

import { z } from 'zod';

/**
 * Common validation messages
 */
export const VALIDATION_MESSAGES = {
  required: 'This field is required',
  email: 'Please enter a valid email address',
  minLength: (length: number) => `Must be at least ${length} characters`,
  maxLength: (length: number) => `Must be at most ${length} characters`,
  url: 'Please enter a valid URL',
  phone: 'Please enter a valid phone number',
  password: {
    minLength: 'Password must be at least 8 characters',
    uppercase: 'Must contain at least one uppercase letter',
    lowercase: 'Must contain at least one lowercase letter',
    number: 'Must contain at least one number',
    special: 'Must contain at least one special character',
  },
} as const;

/**
 * Common field validators
 */
export const validators = {
  required: (message = VALIDATION_MESSAGES.required) => z.string().min(1, { message }),

  email: (message = VALIDATION_MESSAGES.email) => z.string().email({ message }),

  minLength: (length: number, message?: string) =>
    z.string().min(length, {
      message: message || VALIDATION_MESSAGES.minLength(length),
    }),

  maxLength: (length: number, message?: string) =>
    z.string().max(length, {
      message: message || VALIDATION_MESSAGES.maxLength(length),
    }),

  url: (message = VALIDATION_MESSAGES.url) => z.string().url({ message }),

  phone: (message = VALIDATION_MESSAGES.phone) =>
    z.string().regex(/^\+?[\d\s-()]{10,}$/, { message }),

  password: (
    options: {
      minLength?: number;
      requireUppercase?: boolean;
      requireLowercase?: boolean;
      requireNumber?: boolean;
      requireSpecialChar?: boolean;
    } = {},
  ) => {
    const {
      minLength = 8,
      requireUppercase = true,
      requireLowercase = true,
      requireNumber = true,
      requireSpecialChar = true,
    } = options;

    let schema = z.string();

    if (minLength > 0) {
      schema = schema.min(minLength, {
        message: VALIDATION_MESSAGES.password.minLength,
      });
    }

    if (requireUppercase) {
      schema = schema.regex(/[A-Z]/, {
        message: VALIDATION_MESSAGES.password.uppercase,
      });
    }

    if (requireLowercase) {
      schema = schema.regex(/[a-z]/, {
        message: VALIDATION_MESSAGES.password.lowercase,
      });
    }

    if (requireNumber) {
      schema = schema.regex(/[0-9]/, {
        message: VALIDATION_MESSAGES.password.number,
      });
    }

    if (requireSpecialChar) {
      schema = schema.regex(/[^A-Za-z0-9]/, {
        message: VALIDATION_MESSAGES.password.special,
      });
    }

    return schema;
  },
} as const;

/**
 * Create a validation schema for a form
 */
export function createFormSchema<T extends Record<string, any>>(schema: T): z.ZodObject<T> {
  return z.object(schema);
}

/**
 * Infer TypeScript type from a form schema
 */
export type InferFormSchema<T extends z.ZodTypeAny> = z.infer<T>;

interface CookiePreferences {
  essential: boolean;
  analytics: boolean;
  marketing: boolean;
}

interface ConsentRecord {
  preferences: CookiePreferences;
  timestamp: string;
  source: 'direct' | 'banner' | 'preferences';
  version: string;
}

interface ConsentEvent {
  type: 'grant' | 'withdraw' | 'modify';
  preferences: CookiePreferences;
  timestamp: string;
  source: 'direct' | 'banner' | 'preferences';
}

const CONSENT_VERSION = '1.0.0';
const CONSENT_STORAGE_KEY = 'cookieConsent';
const AUDIT_LOG_KEY = 'consentAuditLog';

/**
 * Blocks third-party trackers until user consent is granted.
 * Should be called as early as possible in the application lifecycle.
 */
export function blockTrackersUntilConsent(): void {
  const consent = getConsentStatus();

  // If no consent record exists or analytics/marketing are disabled
  if (!consent || (!consent.analytics && !consent.marketing)) {
    // Create global control variables to prevent script loading
    window.__BLOCK_GA__ = true;
    window.__BLOCK_FB_PIXEL__ = true;
    window.__BLOCK_MARKETING__ = true;

    // Override potential tracking functions
    window.ga = function () {
      console.warn('Analytics blocked due to missing consent');
    };
    window.fbq = function () {
      console.warn('Facebook Pixel blocked due to missing consent');
    };
  }
}

/**
 * Saves the user's consent preferences with audit trail.
 * @param preferences User's cookie preferences
 * @param source Where the consent was given
 */
export function saveConsentChoice(
  preferences: CookiePreferences,
  source: ConsentRecord['source'] = 'banner',
): void {
  const timestamp = new Date().toISOString();

  // Create consent record
  const consentRecord: ConsentRecord = {
    preferences,
    timestamp,
    source,
    version: CONSENT_VERSION,
  };

  // Save to localStorage
  localStorage.setItem(CONSENT_STORAGE_KEY, JSON.stringify(consentRecord));

  // Log consent event
  const event: ConsentEvent = {
    type: 'grant',
    preferences,
    timestamp,
    source,
  };
  auditLog(event);

  // Dispatch event for other parts of the application
  window.dispatchEvent(new CustomEvent('consentUpdated', { detail: consentRecord }));
}

/**
 * Withdraws all optional consent while maintaining essential cookies.
 * As per GDPR Art. 7(3), withdrawal must be as easy as giving consent.
 */
export function withdrawConsent(): void {
  const preferences: CookiePreferences = {
    essential: true, // Essential cookies cannot be withdrawn
    analytics: false,
    marketing: false,
  };

  const timestamp = new Date().toISOString();

  // Update localStorage
  const consentRecord: ConsentRecord = {
    preferences,
    timestamp,
    source: 'direct',
    version: CONSENT_VERSION,
  };

  localStorage.setItem(CONSENT_STORAGE_KEY, JSON.stringify(consentRecord));

  // Log withdrawal
  const event: ConsentEvent = {
    type: 'withdraw',
    preferences,
    timestamp,
    source: 'direct',
  };
  auditLog(event);

  // Dispatch event
  window.dispatchEvent(new CustomEvent('consentUpdated', { detail: consentRecord }));
}

/**
 * Gets the current consent status.
 * @returns Current cookie preferences or null if no consent given
 */
export function getConsentStatus(): CookiePreferences | null {
  const storedConsent = localStorage.getItem(CONSENT_STORAGE_KEY);

  if (!storedConsent) {
    return null;
  }

  try {
    const consentRecord: ConsentRecord = JSON.parse(storedConsent);
    return consentRecord.preferences;
  } catch (e) {
    console.error('Error parsing consent record:', e);
    return null;
  }
}

/**
 * Records consent events for compliance auditing.
 * Maintains a timestamped log of all consent-related actions.
 * @param event The consent event to log
 */
export function auditLog(event: ConsentEvent): void {
  // Get existing log
  const existingLog = localStorage.getItem(AUDIT_LOG_KEY);
  let log: ConsentEvent[] = [];

  if (existingLog) {
    try {
      log = JSON.parse(existingLog);
    } catch (e) {
      console.error('Error parsing audit log:', e);
    }
  }

  // Add new event
  log.push(event);

  // Keep only last 100 events to manage storage size
  if (log.length > 100) {
    log = log.slice(-100);
  }

  // Save updated log
  localStorage.setItem(AUDIT_LOG_KEY, JSON.stringify(log));
}

