test('meta and SEO checks per locale', async ({ page }) => {
  const results: any[] = [];
  for (const lang of ['de', 'en']) {
    const expected = lang === 'de' ? de : en;

    for (const p of pages) {
      const url = `${process.env.E2E_BASE || 'http://localhost:5173'}${p.path}`;
