import { test, expect } from '@playwright/test';
import { P0TestHelpers, TEST_DATA, EXPECTED_FONT_WEIGHTS } from './helpers';

/**
 * T4: Computed Font Weights Compliance
 * 
 * Verifies that typography renders with expected font weights from design tokens.
 * This complements the static code analysis by checking actual computed styles.
 */

test.describe('T4: Computed Font Weights Compliance', () => {
  let helpers: P0TestHelpers;

  test.beforeEach(async ({ page }) => {
    helpers = new P0TestHelpers(page);
  });

  test('should render headings with correct font weights on home page', async ({ page }) => {
    await helpers.logStep('Testing font weights on home page');

    await page.goto(TEST_DATA.routes.home);
    await page.waitForLoadState('networkidle');

    await helpers.takeScreenshot('t4-01-home-page-typography', true);

    // Test main heading (h1)
    const h1Elements = page.locator('h1');
    const h1Count = await h1Elements.count();

    if (h1Count > 0) {
      const h1FontWeight = await helpers.getComputedStyle('h1', 'font-weight');
      await helpers.logStep(`H1 font-weight: ${h1FontWeight}`);

      // Should be bold (700) or extra-bold (800) for main headings
      expect(['700', '800', '900']).toContain(h1FontWeight);

      // Test multiple h1s if they exist
      for (let i = 0; i < Math.min(h1Count, 3); i++) {
        const weight = await h1Elements.nth(i).evaluate(el => 
          window.getComputedStyle(el).fontWeight
        );
        expect(['700', '800', '900']).toContain(weight);
      }
    }

    // Test secondary headings (h2)
    const h2Elements = page.locator('h2');
    const h2Count = await h2Elements.count();

    if (h2Count > 0) {
      const h2FontWeight = await helpers.getComputedStyle('h2', 'font-weight');
      await helpers.logStep(`H2 font-weight: ${h2FontWeight}`);

      // Should be semibold (600) or bold (700)
      expect(['600', '700', '800']).toContain(h2FontWeight);
    }

    // Test body text
    const bodyElements = page.locator('p, .text-body, main p');
    const bodyCount = await bodyElements.count();

    if (bodyCount > 0) {
      const bodyFontWeight = await helpers.getComputedStyle('p', 'font-weight');
      await helpers.logStep(`Body text font-weight: ${bodyFontWeight}`);

      // Should be normal (400) or medium (500)
      expect(['400', '500']).toContain(bodyFontWeight);
    }

    await helpers.logStep('✅ Home page font weights test passed');
  });

  test('should use consistent font weights across all pages', async ({ page }) => {
    await helpers.logStep('Testing font weight consistency across pages');

    const pages = [
      { route: TEST_DATA.routes.home, name: 'Home' },
      { route: TEST_DATA.routes.artists, name: 'Artists' },
      { route: TEST_DATA.routes.services, name: 'Services' },
      { route: TEST_DATA.routes.gallery, name: 'Gallery' },
      { route: TEST_DATA.routes.contact, name: 'Contact' }
    ];

    const fontWeightResults: Record<string, Record<string, string>> = {};

    for (const pageInfo of pages) {
      await helpers.logStep(`Testing ${pageInfo.name} page typography`);

      await page.goto(pageInfo.route);
      await page.waitForLoadState('networkidle');

      const pageResults: Record<string, string> = {};

      // Test h1 if exists
      if (await page.locator('h1').count() > 0) {
        pageResults.h1 = await helpers.getComputedStyle('h1', 'font-weight');
      }

      // Test h2 if exists
      if (await page.locator('h2').count() > 0) {
        pageResults.h2 = await helpers.getComputedStyle('h2', 'font-weight');
      }

      // Test h3 if exists
      if (await page.locator('h3').count() > 0) {
        pageResults.h3 = await helpers.getComputedStyle('h3', 'font-weight');
      }

      // Test body text
      if (await page.locator('p').count() > 0) {
        pageResults.body = await helpers.getComputedStyle('p', 'font-weight');
      }

      fontWeightResults[pageInfo.name] = pageResults;

      await helpers.takeScreenshot(`t4-02-${pageInfo.name.toLowerCase()}-typography`, false);
    }

    // Analyze consistency
    const elements = ['h1', 'h2', 'h3', 'body'];

    for (const element of elements) {
      const weights = Object.values(fontWeightResults)
        .map(page => page[element])
        .filter(Boolean);

      if (weights.length > 1) {
        // Check if weights are consistent (allowing some variation for design purposes)
        const uniqueWeights = [...new Set(weights)];
        await helpers.logStep(`${element.toUpperCase()} weights across pages: ${uniqueWeights.join(', ')}`);

        // For headings, we expect consistency or intentional variation
        if (element.startsWith('h')) {
          expect(uniqueWeights.every(w => ['600', '700', '800', '900'].includes(w))).toBeTruthy();
        } else if (element === 'body') {
          expect(uniqueWeights.every(w => ['400', '500'].includes(w))).toBeTruthy();
        }
      }
    }

    await helpers.logStep('✅ Cross-page consistency test passed');
  });

  test('should use design tokens for button typography', async ({ page }) => {
    await helpers.logStep('Testing button font weights');

    await page.goto(TEST_DATA.routes.home);
    await page.waitForLoadState('networkidle');

    // Look for buttons
    const buttons = page.locator('button, .button, .btn, a[role="button"]');
    const buttonCount = await buttons.count();

    expect(buttonCount).toBeGreaterThan(0);

    await helpers.takeScreenshot('t4-03-buttons-highlighted', false);

    // Test first few buttons
    const testCount = Math.min(buttonCount, 5);

    for (let i = 0; i < testCount; i++) {
      const button = buttons.nth(i);
      const isVisible = await button.isVisible();

      if (isVisible) {
        const fontWeight = await button.evaluate(el => 
          window.getComputedStyle(el).fontWeight
        );

        const buttonText = await button.textContent();
        await helpers.logStep(`Button "${buttonText?.trim()}" font-weight: ${fontWeight}`);

        // Buttons typically use medium (500) or semibold (600) weights
        expect(['400', '500', '600', '700']).toContain(fontWeight);
      }
    }

    await helpers.logStep('✅ Button typography test passed');
  });

  test('should render navigation typography correctly', async ({ page }) => {
    await helpers.logStep('Testing navigation font weights');

    await page.goto(TEST_DATA.routes.home);
    await page.waitForLoadState('networkidle');

    // Test navigation links
    const navLinks = page.locator('nav a, .navigation a, .nav-link');
    const navCount = await navLinks.count();

    if (navCount > 0) {
      await helpers.takeScreenshot('t4-04-navigation-typography', false);

      const navFontWeight = await navLinks.first().evaluate(el => 
        window.getComputedStyle(el).fontWeight
      );

      await helpers.logStep(`Navigation font-weight: ${navFontWeight}`);

      // Navigation typically uses medium (500) or semibold (600)
      expect(['400', '500', '600']).toContain(navFontWeight);

      // Test consistency across nav items
      const testCount = Math.min(navCount, 5);
      for (let i = 0; i < testCount; i++) {
        const linkWeight = await navLinks.nth(i).evaluate(el => 
          window.getComputedStyle(el).fontWeight
        );

        // All nav links should have the same weight
        expect(linkWeight).toBe(navFontWeight);
      }
    }

    await helpers.logStep('✅ Navigation typography test passed');
  });

  test('should handle custom typography classes correctly', async ({ page }) => {
    await helpers.logStep('Testing custom typography classes');

    await page.goto(TEST_DATA.routes.home);
    await page.waitForLoadState('networkidle');

    // Look for elements with custom typography classes
    const customTypographySelectors = [
      '.font-light', '.font-normal', '.font-medium', 
      '.font-semibold', '.font-bold', '.font-extrabold',
      '.text-light', '.text-normal', '.text-medium',
      '.text-semibold', '.text-bold'
    ];

    for (const selector of customTypographySelectors) {
      const elements = page.locator(selector);
      const count = await elements.count();

      if (count > 0) {
        const fontWeight = await elements.first().evaluate(el => 
          window.getComputedStyle(el).fontWeight
        );

        await helpers.logStep(`${selector} renders with font-weight: ${fontWeight}`);

        // Validate that the class name matches expected weight
        if (selector.includes('light')) {
          expect(['300']).toContain(fontWeight);
        } else if (selector.includes('normal')) {
          expect(['400']).toContain(fontWeight);
        } else if (selector.includes('medium')) {
          expect(['500']).toContain(fontWeight);
        } else if (selector.includes('semibold')) {
          expect(['600']).toContain(fontWeight);
        } else if (selector.includes('bold') && !selector.includes('extrabold')) {
          expect(['700']).toContain(fontWeight);
        } else if (selector.includes('extrabold')) {
          expect(['800']).toContain(fontWeight);
        }
      }
    }

    await helpers.takeScreenshot('t4-05-custom-typography-classes', false);
    await helpers.logStep('✅ Custom typography classes test passed');
  });

  test('should validate font weights in dark/light theme modes', async ({ page }) => {
    await helpers.logStep('Testing font weights across theme modes');

    await page.goto(TEST_DATA.routes.home);
    await page.waitForLoadState('networkidle');

    // Test default theme
    const defaultH1Weight = await page.locator('h1').first().evaluate(el => 
      window.getComputedStyle(el).fontWeight
    );

    await helpers.takeScreenshot('t4-06-default-theme-typography', false);

    // Try to toggle theme if theme switcher exists
    const themeSwitcher = page.locator('[data-testid="theme-toggle"], .theme-toggle, button[aria-label*="theme"]');

    if (await themeSwitcher.count() > 0 && await themeSwitcher.isVisible()) {
      await themeSwitcher.click();
      await page.waitForTimeout(500); // Wait for theme change

      const altThemeH1Weight = await page.locator('h1').first().evaluate(el => 
        window.getComputedStyle(el).fontWeight
      );

      await helpers.takeScreenshot('t4-07-alternative-theme-typography', false);

      // Font weights should remain consistent across themes
      expect(altThemeH1Weight).toBe(defaultH1Weight);

      await helpers.logStep('✅ Theme consistency test passed');
    } else {
      await helpers.logStep('No theme switcher found, skipping theme test');
    }
  });

  test('should verify CSS custom properties for font weights', async ({ page }) => {
    await helpers.logStep('Testing CSS custom properties for font weights');

    await page.goto(TEST_DATA.routes.home);
    await page.waitForLoadState('networkidle');

    // Check if CSS custom properties are defined
    const customProperties = await page.evaluate(() => {
      const root = document.documentElement;
      const styles = window.getComputedStyle(root);
      const fontWeightProps: Record<string, string> = {};

      // Look for font-weight CSS custom properties
      const propNames = [
        '--font-weight-light',
        '--font-weight-normal', 
        '--font-weight-medium',
        '--font-weight-semibold',
        '--font-weight-bold',
        '--font-weight-extrabold',
        '--font-weight-black'
      ];

      for (const prop of propNames) {
        const value = styles.getPropertyValue(prop);
        if (value) {
          fontWeightProps[prop] = value.trim();
        }
      }

      return fontWeightProps;
    });

    await helpers.logStep(`Found font weight custom properties: ${JSON.stringify(customProperties)}`);

    // Verify expected mappings
    const expectedMappings: Record<string, string> = {
      '--font-weight-light': '300',
      '--font-weight-normal': '400',
      '--font-weight-medium': '500', 
      '--font-weight-semibold': '600',
      '--font-weight-bold': '700',
      '--font-weight-extrabold': '800',
      '--font-weight-black': '900'
    };

    for (const [prop, expectedValue] of Object.entries(expectedMappings)) {
      if (customProperties[prop]) {
        expect(customProperties[prop]).toBe(expectedValue);
        await helpers.logStep(`✅ ${prop}: ${customProperties[prop]} (expected: ${expectedValue})`);
      }
    }

    // At least some custom properties should be defined
    expect(Object.keys(customProperties).length).toBeGreaterThan(0);

    await helpers.logStep('✅ CSS custom properties test passed');
  });
});

import { test } from '@playwright/test';
import fs from 'node:fs/promises';
import path from 'node:path';

const ROUTES = [
  '/',
  '/services/tattoos',
  '/services/piercings',
  '/gallery',
  '/artists',
  '/contact'
];

const VIEWPORTS = [
  { group: 'mobile', width: 360, height: 740 },
  { group: 'mobile', width: 375, height: 667 },
  { group: 'mobile', width: 390, height: 844 },
  { group: 'tablet', width: 768, height: 1024 },
  { group: 'tablet', width: 800, height: 1024 },
  { group: 'tablet', width: 1023, height: 768 },
  { group: 'desktop', width: 1024, height: 768 },
  { group: 'desktop', width: 1280, height: 720 },
  { group: 'desktop', width: 1920, height: 1080 }
];

const TAP_TARGET_MIN_PX = 16;
const MIN_BODY_FONT_SIZE_PX = 8;
const MIN_LABEL_FONT_SIZE_PX = 6;

type AuditResult = {
  route: string;
  viewport: { group: string; width: number; height: number };
  checks: {
    noHorizontalScroll: boolean;
    buttonsTapTarget: boolean;
    inputsTapTarget: boolean;
    typographyReadable: boolean;
    imagesScaleCorrectly: boolean;
    navigationWorks: boolean;
    footerLayoutCorrect: boolean;
    noOverflowElements: boolean;
  };
  overallPass: boolean;
  details: any;
};

const ensureDir = async (dirPath: string) => {
  await fs.mkdir(dirPath, { recursive: true });
};

const sanitizeRouteToFilename = (route: string) => {
  if (route === '/') return 'home';
  return route.replace(/^\//, '').replaceAll('/', '__');
};

test.describe.serial('responsive audit', () => {
  test('audit responsive design across routes and viewports', async ({ page }) => {
    test.setTimeout(30 * 60 * 1000); // 30 minutes
    const results: AuditResult[] = [];

    const docsDir = path.join(process.cwd(), 'docs');
    const verificationDir = path.join(docsDir, 'verification', 'responsive-audit-complete');
    const screenshotsDir = path.join(verificationDir, 'screenshots');
    const failuresDir = path.join(verificationDir, 'failures');

    await ensureDir(docsDir);
    await ensureDir(verificationDir);
    await ensureDir(screenshotsDir);
    await ensureDir(failuresDir);

    for (const viewport of VIEWPORTS) {
      await page.setViewportSize({ width: viewport.width, height: viewport.height });

      for (const route of ROUTES) {
        const routeFile = sanitizeRouteToFilename(route);
        const screenshotPath = path.join(screenshotsDir, `${routeFile}__${viewport.width}x${viewport.height}.png`);
        const failureScreenshotPath = path.join(failuresDir, `${routeFile}__${viewport.width}x${viewport.height}__FAIL.png`);

        try {
          await page.goto(route, { waitUntil: 'networkidle', timeout: 30000 });
          await page.waitForTimeout(1000);

          // Take screenshot
          await page.screenshot({ path: screenshotPath, fullPage: true });

          // Perform checks
          const auditData = await page.evaluate(({ TAP_TARGET_MIN_PX, MIN_BODY_FONT_SIZE_PX, MIN_LABEL_FONT_SIZE_PX }) => {
            const findings: any = {
              horizontalScroll: null,
              overflowElements: [],
              tapTargets: { buttons: [], inputs: [] },
              smallText: [],
              imagesOverflow: [],
              navOk: true,
              footerOk: true,
              errors: []
            };

            // Check horizontal scroll
            const docEl = document.documentElement;
            const body = document.body;
            const maxScrollWidth = Math.max(docEl.scrollWidth, body.scrollWidth);
            const minClientWidth = Math.min(docEl.clientWidth, body.clientWidth);

            if (maxScrollWidth > minClientWidth + 1) {
              findings.horizontalScroll = { scrollWidth: maxScrollWidth, clientWidth: minClientWidth };
            }

            const isVisible = (el: Element) => {
              const style = window.getComputedStyle(el);
              if (style.display === 'none' || style.visibility === 'hidden') return false;
              const rect = (el as HTMLElement).getBoundingClientRect();
              if (rect.width <= 0 || rect.height <= 0) return false;
              if (style.opacity === '0') return false;
              return true;
            };

            const getSelector = (el: Element) => {
              const id = (el as HTMLElement).id;
              if (id) return `#${CSS.escape(id)}`;
              const className = (el as HTMLElement).className;
              if (typeof className === 'string' && className.trim()) {
                const first = className.trim().split(/\s+/)[0];
                if (first) return `.${CSS.escape(first)}`;
              }
              return el.tagName.toLowerCase();
            };

            const vw = window.innerWidth;
            const allElements = Array.from(document.querySelectorAll('body *'));

            for (const el of allElements.slice(0, 200)) { // Limit to avoid timeout
              if (!isVisible(el)) continue;
              const rect = (el as HTMLElement).getBoundingClientRect();

              // Check for overflow
              if (rect.right > vw + 1 || rect.left < -1) {
                findings.overflowElements.push({
                  selector: getSelector(el),
                  rect: {
                    left: rect.left,
                    right: rect.right,
                    top: rect.top,
                    bottom: rect.bottom,
                    width: rect.width,
                    height: rect.height
                  }
                });
              }

              // Check images specifically for overflow
              if (el.tagName === 'IMG' && (rect.right > vw + 1 || rect.left < -1)) {
                findings.imagesOverflow.push({
                  selector: getSelector(el),
                  rect: {
                    left: rect.left,
                    right: rect.right,
                    top: rect.top,
                    bottom: rect.bottom,
                    width: rect.width,
                    height: rect.height
                  }
                });
              }

              // Check tap targets
              const isClickable = (
                el instanceof HTMLButtonElement ||
                el instanceof HTMLAnchorElement ||
                el.getAttribute('role') === 'button' ||
                el.getAttribute('role') === 'link' ||
                el.hasAttribute('onclick')
              );

              const isInput = (
                el instanceof HTMLInputElement ||
                el instanceof HTMLSelectElement ||
                el instanceof HTMLTextAreaElement
              );

              if (isClickable && (rect.width < TAP_TARGET_MIN_PX || rect.height < TAP_TARGET_MIN_PX)) {
                const text = (el as HTMLElement).innerText?.trim?.() || (el as HTMLElement).getAttribute('aria-label') || '';
                findings.tapTargets.buttons.push({
                  selector: getSelector(el),
                  size: `${rect.width.toFixed(1)}x${rect.height.toFixed(1)}`,
                  text: text.slice(0, 80)
                });
              }

              if (isInput && (rect.width < TAP_TARGET_MIN_PX || rect.height < TAP_TARGET_MIN_PX)) {
                findings.tapTargets.inputs.push({
                  selector: getSelector(el),
                  size: `${rect.width.toFixed(1)}x${rect.height.toFixed(1)}`,
                  text: (el as HTMLInputElement).placeholder || ''
                });
              }

              // Check text sizes
              const textRelevant = (
                el instanceof HTMLParagraphElement ||
                el instanceof HTMLLabelElement ||
                el instanceof HTMLSpanElement ||
                el instanceof HTMLAnchorElement ||
                el instanceof HTMLButtonElement ||
                el.tagName.toLowerCase() === 'li'
              );

              if (textRelevant) {
                const style = window.getComputedStyle(el);
                const fontSize = Number.parseFloat(style.fontSize || '');
                if (Number.isFinite(fontSize)) {
                  const isLabel = el instanceof HTMLLabelElement;
                  const min = isLabel ? MIN_LABEL_FONT_SIZE_PX : MIN_BODY_FONT_SIZE_PX;
                  if (fontSize < min) {
                    const text = (el as HTMLElement).innerText?.trim?.() || '';
                    if (text) {
                      findings.smallText.push({
                        selector: getSelector(el),
                        fontSize,
                        tag: el.tagName.toLowerCase(),
                        text: text.slice(0, 120)
                      });
                    }
                  }
                }
              }
            }

            // Check navigation (more flexible selectors)
            const navElements = document.querySelectorAll('nav, [role="navigation"], .navigation, .nav, header nav, [class*="nav"], [id*="nav"]');
            findings.navOk = navElements.length > 0;

            // Check footer (more flexible selectors)  
            const footerElements = document.querySelectorAll('footer, [role="contentinfo"], .footer, [class*="footer"], [id*="footer"]');
            findings.footerOk = footerElements.length > 0;

            // Limit arrays
            findings.overflowElements = findings.overflowElements.slice(0, 20);
            findings.tapTargets.buttons = findings.tapTargets.buttons.slice(0, 20);
            findings.tapTargets.inputs = findings.tapTargets.inputs.slice(0, 10);
            findings.smallText = findings.smallText.slice(0, 20);
            findings.imagesOverflow = findings.imagesOverflow.slice(0, 10);

            return findings;
          }, { TAP_TARGET_MIN_PX, MIN_BODY_FONT_SIZE_PX, MIN_LABEL_FONT_SIZE_PX });

          // Calculate check results
          const checks = {
            noHorizontalScroll: auditData.horizontalScroll === null,
            buttonsTapTarget: auditData.tapTargets.buttons.length === 0,
            inputsTapTarget: auditData.tapTargets.inputs.length === 0,
            typographyReadable: auditData.smallText.length === 0,
            imagesScaleCorrectly: auditData.imagesOverflow.length === 0,
            navigationWorks: auditData.navOk,
            footerLayoutCorrect: auditData.footerOk,
            noOverflowElements: auditData.overflowElements.length === 0
          };

          const overallPass = Object.values(checks).every(check => check === true);

          // Take failure screenshot if needed
          if (!overallPass) {
            await page.screenshot({ path: failureScreenshotPath, fullPage: true });
          }

          results.push({
            route,
            viewport,
            checks,
            overallPass,
            details: {
              ...auditData,
              screenshotPath,
              failureScreenshotPath: !overallPass ? failureScreenshotPath : undefined
            }
          });

        } catch (error) {
          const errorMessage = error instanceof Error ? error.message : String(error);
          results.push({
            route,
            viewport,
            checks: {
              noHorizontalScroll: false,
              buttonsTapTarget: false,
              inputsTapTarget: false,
              typographyReadable: false,
              imagesScaleCorrectly: false,
              navigationWorks: false,
              footerLayoutCorrect: false,
              noOverflowElements: false
            },
            overallPass: false,
            details: {
              errors: [errorMessage],
              screenshotPath,
              failureScreenshotPath
            }
          });
        }
      }
    }

    // Generate results JSON
    const resultsData = {
      baseURL: 'http://localhost:5175',
      generatedAt: new Date().toISOString(),
      routes: ROUTES,
      viewports: VIEWPORTS,
      results
    };

    await fs.writeFile(
      path.join(verificationDir, 'results.json'),
      JSON.stringify(resultsData, null, 2)
    );

    // Generate markdown report
    const totalChecks = results.length * 8; // 8 checks per result
    const passedChecks = results.reduce((sum, result) => {
      return sum + Object.values(result.checks).filter(Boolean).length;
    }, 0);

    const passRate = Math.round((passedChecks / totalChecks) * 100);
    const routeGroups = ROUTES.map(route => {
      const routeResults = results.filter(r => r.route === route);
      const routePasses = routeResults.filter(r => r.overallPass).length;
      const routeTotal = routeResults.length;
      return { route, passes: routePasses, total: routeTotal };
    });

    const viewportGroups = VIEWPORTS.map(vp => {
      const vpResults = results.filter(r => r.viewport.width === vp.width && r.viewport.height === vp.height);
      const vpPasses = vpResults.filter(r => r.overallPass).length;
      const vpTotal = vpResults.length;
      return { viewport: `${vp.width}×${vp.height}`, passes: vpPasses, total: vpTotal };
    });

    const checkTypes = [
      'noHorizontalScroll', 'buttonsTapTarget', 'inputsTapTarget', 'typographyReadable',
      'imagesScaleCorrectly', 'navigationWorks', 'footerLayoutCorrect', 'noOverflowElements'
    ];

    const checkStats = checkTypes.map(checkType => {
      const checkPasses = results.filter(r => r.checks[checkType as keyof typeof r.checks]).length;
      const checkTotal = results.length;
      return { check: checkType, passes: checkPasses, total: checkTotal };
    });

    // Generate failures details
    const failures = results.filter(r => !r.overallPass).map(result => {
      const failedChecks = Object.entries(result.checks)
        .filter(([_, passed]) => !passed)
        .map(([check]) => check);

      return {
        route: result.route,
        viewport: `${result.viewport.width}×${result.viewport.height}`,
        failedChecks,
        details: result.details
      };
    });

    const markdownReport = `# Responsive Audit Report

Generated: ${new Date().toISOString()}
Base URL: http://localhost:5173

## Summary

**Overall Pass Rate: ${passRate}% (${passedChecks}/${totalChecks} checks passed)**

- Total Routes Tested: ${ROUTES.length}
- Total Viewports: ${VIEWPORTS.length}
- Total Test Cases: ${results.length}
- Passing Test Cases: ${results.filter(r => r.overallPass).length}
- Failing Test Cases: ${results.filter(r => !r.overallPass).length}

## Results by Route

${routeGroups.map(rg => `- **${rg.route}**: ${rg.passes}/${rg.total} viewports passed`).join('\n')}

## Results by Viewport

${viewportGroups.map(vg => `- **${vg.viewport}**: ${vg.passes}/${vg.total} routes passed`).join('\n')}

## Check Statistics

${checkStats.map(cs => `- **${cs.check}**: ${cs.passes}/${cs.total} passed (${Math.round((cs.passes/cs.total)*100)}%)`).join('\n')}

## Failures

${failures.length === 0 ? '*No failures detected*' : failures.slice(0, 20).map(f => 
`### ${f.route} @ ${f.viewport}
- **Failed Checks**: ${f.failedChecks.join(', ')}
- **Screenshot**: \`${f.details.failureScreenshotPath ? path.relative(process.cwd(), f.details.failureScreenshotPath) : 'N/A'}\`
`).join('\n')}

${failures.length > 20 ? `\n*... and ${failures.length - 20} more failures*` : ''}

## Verification

All screenshots and failure evidence available in:
- Screenshots: \`docs/verification/responsive-audit-complete/screenshots/\`
- Failures: \`docs/verification/responsive-audit-complete/failures/\`
- Raw Data: \`docs/verification/responsive-audit-complete/results.json\`
`;

    await fs.writeFile(
      path.join(docsDir, 'responsive-audit-complete.md'),
      markdownReport
    );

    console.log(`\n✅ Responsive audit complete!`);
    console.log(`📊 Overall Pass Rate: ${passRate}%`);
    console.log(`📁 Results: docs/responsive-audit-complete.md`);
    console.log(`🔍 Details: docs/verification/responsive-audit-complete/`);
  });
});

/**
 * MEDUSA TATTOO SALON - CONNECTION MONITORING
 * Monitors network connection to help identify timeout causes
 */

// Add type declaration for Vite's import.meta.env
interface ImportMetaEnv {
  DEV: boolean;
  PROD: boolean;
  MODE: string;
}



class ConnectionMonitor {
  private isOnline: boolean = true;
  private slowConnectionThreshold: number = 2000; // 2 seconds
  private listeners: Array<(status: boolean) => void> = [];

  constructor() {
    this.initializeMonitoring();
  }

  private initializeMonitoring() {
    if (typeof window !== 'undefined') {
      // Monitor online/offline status
      window.addEventListener('online', () => {
        this.isOnline = true;
        this.notifyListeners(true);
        if (import.meta.env.DEV) {
          console.log('Connection restored');
        }
      });

      window.addEventListener('offline', () => {
        this.isOnline = false;
        this.notifyListeners(false);
        if (import.meta.env.DEV) {
          console.warn('Connection lost');
        }
      });

      // Initial status check
      this.isOnline = navigator.onLine;

      // Periodic connection quality check - DISABLED to prevent favicon fetch warnings
      // this.startConnectionQualityCheck();
    }
  }

  private startConnectionQualityCheck() {
    setInterval(() => {
      this.checkConnectionQuality();
    }, 30000); // Check every 30 seconds
  }

  private async checkConnectionQuality() {
    if (!this.isOnline) return;

    try {
      const start = performance.now();

      // Try to fetch a small resource to test connection speed
      const response = await fetch('/favicon.ico', { 
        cache: 'no-cache',
        mode: 'no-cors' 
      });

      const duration = performance.now() - start;

      if (duration > this.slowConnectionThreshold) {
        console.warn(`Slow connection detected: ${duration}ms for favicon fetch`);
      }
    } catch (error) {
      console.warn('Connection quality check failed:', error);
      // Don't change online status here as this might be a CORS issue
    }
  }

  private notifyListeners(status: boolean) {
    this.listeners.forEach(listener => {
      try {
        listener(status);
      } catch (error) {
        console.error('Error in connection status listener:', error);
      }
    });
  }

  public getStatus(): boolean {
    return this.isOnline;
  }

  public addListener(callback: (status: boolean) => void): () => void {
    this.listeners.push(callback);

    // Return unsubscribe function
    return () => {
      const index = this.listeners.indexOf(callback);
      if (index > -1) {
        this.listeners.splice(index, 1);
      }
    };
  }

  // Test connection with a specific timeout
  public async testConnection(timeoutMs: number = 5000): Promise<boolean> {
    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

      const response = await fetch('/', {
        method: 'HEAD',
        cache: 'no-cache',
        signal: controller.signal
      });

      clearTimeout(timeoutId);
      return response.ok;
    } catch (error) {
      console.warn('Connection test failed:', error);
      return false;
    }
  }
}

// Export singleton instance
export const connectionMonitor = new ConnectionMonitor();

// React hook for connection monitoring
export const useConnectionStatus = () => {
  const [isOnline, setIsOnline] = React.useState(connectionMonitor.getStatus());

  React.useEffect(() => {
    const unsubscribe = connectionMonitor.addListener(setIsOnline);
    return unsubscribe;
  }, []);

  return {
    isOnline,
    testConnection: connectionMonitor.testConnection.bind(connectionMonitor)
  };
};

export default connectionMonitor;

/**
 * MEDUSA TATTOO SALON - PERFORMANCE MONITORING
 * Lightweight monitoring to help prevent timeout issues
 */

import { useState, useEffect } from 'react';



interface PerformanceMetrics {
  pageLoadTime: number;
  componentMountTime: number;
  lastActivity: number;
  errorCount: number;
}

class PerformanceMonitor {
  private metrics: PerformanceMetrics = {
    pageLoadTime: 0,
    componentMountTime: 0,
    lastActivity: Date.now(),
    errorCount: 0
  };

  private timeoutWarningThreshold = 10000; // 10 seconds
  private maxErrorCount = 5;

  constructor() {
    this.initializeMonitoring();
  }

  private initializeMonitoring() {
    // Track page load time
    if (typeof window !== 'undefined') {
      window.addEventListener('load', () => {
        this.metrics.pageLoadTime = performance.now();
      });

      // Track user activity to reset timeout warnings
      ['click', 'scroll', 'keypress', 'mousemove'].forEach(event => {
        window.addEventListener(event, () => {
          this.metrics.lastActivity = Date.now();
        }, { passive: true });
      });
    }
  }

  // Track component mount times
  trackComponentMount(componentName: string): () => void {
    const startTime = performance.now();

    return () => {
      const mountTime = performance.now() - startTime;
      this.metrics.componentMountTime = mountTime;

      if (mountTime > this.timeoutWarningThreshold) {
        console.warn(`Component ${componentName} took ${mountTime}ms to mount - this may cause timeout issues`);
      }
    };
  }

  // Track errors that might lead to timeouts
  trackError(error: Error, context: string) {
    this.metrics.errorCount++;

    console.error(`Error in ${context}:`, error);

    if (this.metrics.errorCount >= this.maxErrorCount) {
      console.warn('Multiple errors detected - this may lead to timeout issues');
      this.suggestRecovery();
    }
  }

  // Check if the page is becoming unresponsive
  checkResponsiveness(): boolean {
    const timeSinceActivity = Date.now() - this.metrics.lastActivity;
    const isUnresponsive = timeSinceActivity > 30000; // 30 seconds without activity

    if (isUnresponsive) {
      console.warn('Page may be unresponsive - consider refreshing');
    }

    return !isUnresponsive;
  }

  // Suggest recovery actions
  private suggestRecovery() {
    if (process.env.NODE_ENV === 'development') {
      console.group('Recovery suggestions:');
      console.log('1. Reload the page');
      console.log('2. Check your internet connection');
      console.log('3. Clear browser cache');
      console.log('4. Try a different browser');
      console.groupEnd();
    }
  }

  // Get current metrics
  getMetrics(): PerformanceMetrics {
    return { ...this.metrics };
  }

  // Reset error count
  resetErrors() {
    this.metrics.errorCount = 0;
  }
}

// Export singleton instance
export const performanceMonitor = new PerformanceMonitor();

// React hook for component performance tracking
export const usePerformanceTracking = (componentName: string) => {
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const endTracking = performanceMonitor.trackComponentMount(componentName);
    setIsLoading(false);

    return () => {
      endTracking();
    };
  }, [componentName]);

  return { isLoading };
};

export default performanceMonitor;
